<?php
namespace App\Http\Controllers\Admin; use App\Http\Controllers\Controller; use App\Http\Requests\Admin\MasterDataRequest; use App\Models\{Region,Branch,Location,Nationality,Currency,Language}; use App\Services\Admin\ActivityLogger; use Illuminate\Http\Request;
class MasterDataController extends Controller { private array $map=['regions'=>Region::class,'branches'=>Branch::class,'locations'=>Location::class,'nationalities'=>Nationality::class,'currencies'=>Currency::class,'languages'=>Language::class]; private function model($type){abort_unless(isset($this->map[$type]),404); return $this->map[$type];} public function index(string $type){$m=$this->model($type); return view('admin.master-data.index',['type'=>$type,'items'=>$m::latest()->paginate(15)]);} public function create(string $type){$this->model($type); return view('admin.master-data.form',['type'=>$type,'item'=>null,'regions'=>Region::all()]);} public function store(MasterDataRequest $r,string $type,ActivityLogger $l){$m=$this->model($type); $item=$m::create($r->validated()); $l->log('created','Created '.$type,$item); return redirect()->route('admin.master-data.index',$type);} public function edit(string $type,int $id){$m=$this->model($type); return view('admin.master-data.form',['type'=>$type,'item'=>$m::findOrFail($id),'regions'=>Region::all()]);} public function update(MasterDataRequest $r,string $type,int $id,ActivityLogger $l){$m=$this->model($type); $item=$m::findOrFail($id); $item->update($r->validated()); $l->log('updated','Updated '.$type,$item); return redirect()->route('admin.master-data.index',$type);} public function destroy(string $type,int $id,ActivityLogger $l){$m=$this->model($type); $item=$m::findOrFail($id); $l->log('deleted','Deleted '.$type,$item); $item->delete(); return back();} }
